              }}
            />
            <div className="login-logo-fallback" style={{ display: 'none' }}>
              SENA
            </div>
          </div>

          <div className="login-panel-left-body">
            <h1>Plataforma de Gestión Institucional</h1>
            <p>
              Accede a tus servicios, trámites y recursos del Servicio
              Nacional de Aprendizaje desde un solo lugar.
            </p>
          </div>

          <div className="login-panel-left-footer">
            © 2025 SENA · Todos los derechos reservados
          </div>
        </div>

        {/* ── Panel derecho ── */}
        <div className="login-panel-right">
          <div className="login-form-wrap">

            <div className="login-badge">
              <div className="login-badge-dot" />
              Sistema activo
            </div>

            <p className="login-eyebrow">Bienvenido</p>
            <h2 className="login-title">Inicia sesión en tu cuenta</h2>

            {error && (
              <div className="login-error">{error}</div>
            )}

            <form onSubmit={handleSubmit}>
              <div className="login-field">
                <label className="login-label">Correo electrónico</label>
                <input
                  className="login-input"
                  type="email"
                  name="correoElectronico"
                  value={formData.correoElectronico}
                  onChange={handleChange}
                  placeholder="tu@correo.com"
                  required
                />
              </div>

              <div className="login-field">
                <label className="login-label">Contraseña</label>
                <input
                  className="login-input"
                  type="password"
                  name="password"
                  value={formData.password}
                  onChange={handleChange}
                  placeholder="••••••••"
                  required
                />
              </div>

              <Link to="/recuperar-password" className="login-forgot">
                ¿Olvidaste tu contraseña?
              </Link>

              <button
                type="submit"
                className="login-btn"
                disabled={loading}
              >
                {loading ? 'Iniciando sesión...' : 'Iniciar sesión'}
              </button>
            </form>

            <div className="login-divider">o</div>

            <div className="login-register">
              ¿No tienes cuenta?{' '}
              <Link to="/registro">Regístrate aquí</Link>
            </div>

          </div>
        </div>

      </div>
    </>
  );
};

export default Login;
